[Form]
public class ETGITMTableOutbound extends FormRun
{
    private NumberSeqFormHandler numberSeqFormHandler;
    private ETGITMTableFormOutbound shipTableForm;
    private InventDimCtrl_Frm inventDimFormSetup;

    private boolean jumpToMainTable;
    private boolean inShipLineDeleteMarked;

}

protected void closeForm()
{
    if (element.args().callerName() == formStr(ITMTableListPage) || 
        element.args().callerName() == formStr(ETGITMTableListPageOutbound))
    {
        element.close();
    }
}

public void close()
{
    if (numberSeqFormHandler)
    {
        numberSeqFormHandler.formMethodClose();
    }

    super();
}

private void enablePorts()
{
    if (ITMFeatureManagementVisibilityManager::isEnabled())
    {
        ITMTable_ds.object(fieldNum(ITMTable, ShipFromPort)).allowEdit(false);
        ITMTable_ds.object(fieldNum(ITMTable, ShipFromPort)).skip(true);

        ITMTable_ds.object(fieldNum(ITMTable, ShipToPort)).allowEdit(false);
        ITMTable_ds.object(fieldNum(ITMTable, ShipToPort)).skip(true);
    }
}

public void init()
{
    super();

    jumpToMainTable = SysFormRun::isCalledFromJumpRef(element.args(), fieldNum(ITMTable, ShipId));

    shipTableForm = ETGITMTableFormOutbound::construct();

    if (element.args() && element.args().dataset() == tableNum(SalesTable))
    {
        shipTableForm.parmSalesTable(element.args().record());
    }

    element.updateDesign(InventDimFormDesignUpdate::Init);

    element.enablePorts();
}

public Object inventDimSetupObject()
{
    return inventDimFormSetup;
}

public NumberSeqFormHandler numberSeqFormHandler()
{
    if (!numberSeqFormHandler)
    {
        numberSeqFormHandler = numberSeqFormHandler::newForm(ITMParameters::numRefShipId().NumberSequenceId,
                                                             element,
                                                             ITMTable_ds,
                                                             fieldNum(ITMTable, ShipId)
                                                            );
    }
    return numberSeqFormHandler;
}

public void setTitleText()
{
    HeaderTitle.text(strFmt("@InboundTransportationManagement:TitleText", ITMTable.ShipId, ITMTable.ShipDescription));
}

public void updateDesign(InventDimFormDesignUpdate _mode)
{
    switch (_mode)
    {
        case InventDimFormDesignUpdate::Init:
            if (!inventDimFormSetup)
            {
                inventDimFormSetup = InventDimCtrl_Frm::newFromFormOutboundETG(element);
            }

            inventDimFormSetup.parmSkipOnHandLookUp(true);
            // No break. Statement will fall through.

        case InventDimFormDesignUpdate::Active:
            inventDimFormSetup.formSetControls(true);
            break;

        default: 
            throw error(strFmt("@SYS54195", funcName()));
    }
}

public ETGITMTableFormOutbound getShipTableFormObject()
{
    return shipTableForm;
}

public void delete()
{
    ttsBegin;

    element.numberSeqFormHandler().formMethodDataSourceDelete();

    super();

    ttsCommit;
}

public boolean validateWrite()
{
    boolean ret;

    ret = super();        
    ret = ret && element.numberSeqFormHandler().formMethodDataSourceValidateWrite(ret);

    return ret;
}

public void write()
{
    ttsBegin;

    super();

    element.numberSeqFormHandler().formMethodDataSourceWrite();

    ttsCommit;
}

public void linkActive()
{
    element.numberSeqFormHandler().formMethodDataSourceLinkActive();

    super();
}

public void create(boolean _append = false)
{
    ITMTable newShipTable;
    boolean shipTableFormCreate;

    shipTableFormCreate = shipTableForm.create();

    if (shipTableFormCreate)
    {
        newShipTable = ITMTable::find(shipTableForm.parmNewShipId());

        if (newShipTable)
        {
            super(_append);

            ITMTable.data(newShipTable);

            this.setCurrent();

            shipTableForm.shipEditorForm(newShipTable);

            element.closeForm();
        }
    }
    else
    {
        element.closeForm();
    }
}

public int active()
{
    int ret;

    ret = super();

    element.setTitleText();

    return ret;
}

public void deleteMarked()
{
    ITMLine deletedShipLine;

    deletedShipLine.data(this.cursor());

    inShipLineDeleteMarked = true;

    super();

    ITMLine::reNumber(deletedShipLine, 0);
    this.research(true);

    inShipLineDeleteMarked = false;
}

public void delete()
{
    ITMLine deletedShipLine;

    deletedShipLine.data(this.cursor());

    super();

    if (!inShipLineDeleteMarked)
    {
        ITMLine::reNumber(deletedShipLine, 0);
        this.research(true);
    }
}

public int active()
{
    int ret;

    ret = super();

    element.updateDesign(InventDimFormDesignUpdate::Active);

    return ret;
}

public void init()
{
    super();

    ITMLine_ds.cacheAddMethod(tableMethodStr(ITMLine, receivedInTotal));
    ITMLine_ds.cacheAddMethod(tableMethodStr(ITMLine, purchStatus));
    ITMLine_ds.cacheAddMethod(tableMethodStr(ITMLine, costPrice));
    ITMLine_ds.cacheAddMethod(tableMethodStr(ITMLine, itemName));
    ITMLine_ds.cacheAddMethod(tableMethodStr(ITMLine, purchPrice));
    ITMLine_ds.cacheAddMethod(tableMethodStr(ITMLine, lineAmount));
}

public void jumpRef()
{
    ITMLine::jumpRefPurchTable(ITMLine, element);
}

public void jumpRef()
{
    ITMLine::jumpRefShipContainers(ITMLine, element);
}

public void clicked()
{
    super();

    shipTableForm.shipEditorForm(ITMTable);
}
